// Display + condensed fonts for the handbag-promo recreation, embedded as
// base64 `data:` URLs so the composition is fully self-contained and renders
// with the identical typeface in both the browser preview (FontFace) and the
// Node render (@napi-rs/canvas, via Route B's font bridge). Latin subsets from
// Google Fonts (Anton, Oswald — SIL Open Font License).

// "Anton" — a single-weight heavy condensed grotesque: the poster headlines
// (FASHIONABLE HANDBAG / GET IT NOW) and the outline display type.
export const DISPLAY_FAMILY = "Anton";
export const DISPLAY_DATA_URL = "data:font/woff2;base64,";

// "Oswald" 600 / 700 — a tighter condensed sans for the sub-labels, the film
// strip markings and the URL caption.
export const COND_FAMILY = "Oswald";
export const COND_600_DATA_URL = "data:font/woff2;base64,";
export const COND_700_DATA_URL = "data:font/woff2;base64,";
